const crypto = require('node:crypto');

const password = '123456';

const hashPassword = (data) => {
  const hash = crypto.createHash('sha256');
  hash.update(data);
  return hash.digest('hex');
};

const hashedPassword = hashPassword(password);

// Assume this is the stored user password hash in the database
const storedHashedPassword = hashedPassword;

// User-entered password
const userInputPassword = '123456';

const hashedInputPassword = hashPassword(userInputPassword);

// Compare the hashed user input with the stored hash from the database
if (hashedInputPassword === storedHashedPassword) {
  console.log('Password correct, authentication successful!');
} else {
  console.log('Password incorrect, authentication failed!');
}

